def subset_sum(xs, target):
    def helper(xs, target, index):
        if target == 0:
            return True
        if index == len(xs) or target < 0:
            return False
        return helper(xs, target - xs[index], index + 1) or helper(xs, target, index + 1)

    return helper(xs, target, 0)
